function tensor_inverse6(A::AbstractArray{T, 3}) where T 
    out = similar(A)

    tensor_inverse6!(out, A)
    
    out 
end

function tensor_inverse6!(out::AbstractArray{T, 3}, A::AbstractArray{T, 3}) where T 
    @assert size(A, 1) == size(A, 2) == 6
    @assert size(A) == size(out)

    backend = get_backend(out)
    inv66! = inv66_kernel!(backend)

    inv66!(out, A, ndrange = size(A, 3))

    nothing
end

function ChainRulesCore.rrule(::typeof(tensor_inverse6), A::AT) where {T, AT<:AbstractArray{T, 3}}
    out = tensor_inverse6(A)
    
    function tensor_inverse_pullback(out_diff::AT)
        A_diff = zero(out_diff)
        out_diff_copy = copy(out_diff)
        A_copy = copy(A)
        out_copy = copy(out)
        Enzyme.autodiff(Enzyme.Reverse, tensor_inverse6!, Enzyme.Const, Enzyme.Duplicated(out_copy, out_diff_copy), Enzyme.Duplicated(A_copy, A_diff))

        NoTangent(), A_diff 
    end 
    out, tensor_inverse_pullback 
end 